class DeviceIntegrityChecker {
    
    static let shared = DeviceIntegrityChecker()
    
    private init() {}
    
    func performComprehensiveSecurityCheck() -> SecurityCheckResult {
        var failedChecks: [String] = []
        var warningChecks: [String] = []
        
        if isJailbroken() {
            failedChecks.append("Jailbreak detected")
        }
        
        if isDebuggerAttached() {
            failedChecks.append("Debugger attached")
        }
        
        if isSuspiciousEnvironment() {
            warningChecks.append("Suspicious environment detected")
        }
        
        if hasCodeInjection() {
            failedChecks.append("Code injection detected")
        }
        
        if !verifyAppIntegrity() {
            failedChecks.append("App integrity compromised")
        }
        
        let riskLevel: SecurityRiskLevel
        if !failedChecks.isEmpty {
            riskLevel = .critical
        } else if !warningChecks.isEmpty {
            riskLevel = .elevated
        } else {
            riskLevel = .normal
        }
        
        return SecurityCheckResult(
            riskLevel: riskLevel,
            failedChecks: failedChecks,
            warningChecks: warningChecks
        )
    }
    
    private func isJailbroken() -> Bool {
        #if targetEnvironment(simulator)
        return false
        #else
        
        let jailbreakPaths = [
            "/Applications/Cydia.app",
            "/Library/MobileSubstrate/MobileSubstrate.dylib",
            "/bin/bash",
            "/usr/sbin/sshd",
            "/etc/apt",
            "/private/var/lib/apt/",
            "/private/var/lib/cydia",
            "/private/var/stash",
            "/private/var/tmp/cydia.log",
            "/Applications/RockApp.app",
            "/Applications/Icy.app",
            "/usr/libexec/sftp-server",
            "/usr/bin/sshd",
            "/Applications/WinterBoard.app",
            "/Applications/SBSettings.app",
            "/Applications/MxTube.app",
            "/Applications/IntelliScreen.app",
            "/Library/MobileSubstrate/DynamicLibraries/Veency.plist",
            "/Library/MobileSubstrate/DynamicLibraries/LiveClock.plist",
            "/usr/libexec/cydia/",
            "/System/Library/LaunchDaemons/com.saurik.Cydia.Startup.plist",
            "/System/Library/LaunchDaemons/com.ikey.bbot.plist",
            "/.installed_unc0ver",
            "/.bootstrapped_electra",
            "/usr/share/jailbreak/injectme.plist",
            "/etc/apt/sources.list.d/electra.list",
            "/etc/apt/sources.list.d/sileo.sources",
            "/.cydia_no_stash",
            "/var/cache/apt",
            "/var/lib/cydia",
            "/var/log/syslog",
            "/bin/sh",
            "/etc/ssh/sshd_config"
        ]
        
        for path in jailbreakPaths {
            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        
        if canOpenSuspiciousURL() {
            return true
        }
        
        if canWriteToRestrictedPath() {
            return true
        }
        
        if hasSuspiciousDylibs() {
            return true
        }
        
        if checkFork() {
            return true
        }
        
        if checkSymbolicLinks() {
            return true
        }
        
        return false
        #endif
    }
    
    private func canOpenSuspiciousURL() -> Bool {
        guard let url = URL(string: "cydia://package/com.example.package") else { return false }
        return UIApplication.shared.canOpenURL(url)
    }
    
    private func canWriteToRestrictedPath() -> Bool {
        let testPath = "/private/jailbreak_test.txt"
        do {
            try "test".write(toFile: testPath, atomically: true, encoding: .utf8)
            try FileManager.default.removeItem(atPath: testPath)
            return true
        } catch {
            return false
        }
    }
    
    private func hasSuspiciousDylibs() -> Bool {
        let suspiciousLibraries = [
            "MobileSubstrate",
            "SubstrateInserter",
            "SubstrateLoader",
            "SSLKillSwitch",
            "Cycript",
            "FridaGadget",
            "frida"
        ]
        
        for i in 0..<_dyld_image_count() {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName)
                for suspicious in suspiciousLibraries {
                    if name.contains(suspicious) {
                        return true
                    }
                }
            }
        }
        return false
    }
    
    private func checkFork() -> Bool {
        let result = fork()
        if result >= 0 {
            if result > 0 {
                kill(result, SIGKILL)
            }
            return true
        }
        return false
    }
    
    private func checkSymbolicLinks() -> Bool {
        do {
            let path = "/Applications"
            let attributes = try FileManager.default.attributesOfItem(atPath: path)
            if let fileType = attributes[.type] as? FileAttributeType {
                return fileType == .typeSymbolicLink
            }
        } catch {}
        return false
    }
    
    private func isDebuggerAttached() -> Bool {
        var info = kinfo_proc()
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        var size = MemoryLayout<kinfo_proc>.stride
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        
        if result != 0 {
            return false
        }
        
        return (info.kp_proc.p_flag & P_TRACED) != 0
    }
    
    private func isSuspiciousEnvironment() -> Bool {
        let suspiciousEnvVars = ["DYLD_INSERT_LIBRARIES", "DYLD_FRAMEWORK_PATH", "DYLD_LIBRARY_PATH"]
        for envVar in suspiciousEnvVars {
            if getenv(envVar) != nil {
                return true
            }
        }
        return false
    }
    
    private func hasCodeInjection() -> Bool {
        var count: UInt32 = 0
        guard let classList = objc_copyClassList(&count) else { return false }
        
        let suspiciousClasses = ["FridaGadget", "Cycript", "SubstrateLoader"]
        
        for i in 0..<Int(count) {
            let className = String(cString: class_getName(classList[i]))
            for suspicious in suspiciousClasses {
                if className.contains(suspicious) {
                    return true
                }
            }
        }
        return false
    }
    
    private func verifyAppIntegrity() -> Bool {
        guard let executablePath = Bundle.main.executablePath else { return false }
        guard let executableData = try? Data(contentsOf: URL(fileURLWithPath: executablePath)) else { return false }
        
        let hash = SHA256.hash(data: executableData)
        let hashString = hash.compactMap { String(format: "%02x", $0) }.joined()
        
        let storedHash = UserDefaults.standard.string(forKey: "app_integrity_hash")
        
        if storedHash == nil {
            UserDefaults.standard.set(hashString, forKey: "app_integrity_hash")
            return true
        }
        
        return storedHash == hashString
    }
}

enum SecurityRiskLevel {
    case normal
    case elevated
    case critical
}

struct SecurityCheckResult {
    let riskLevel: SecurityRiskLevel
    let failedChecks: [String]
