// MARK: - Secure Storage Manager

class SecureStorageManager {
    
    static let shared = SecureStorageManager()
    
    private let keychainService = "com.cryptowallet.secure"
    private let privateKeyTag = "com.cryptowallet.privatekey"
    
    private init() {}
    
    func storePrivateKey(_ privateKey: Data, withBiometrics: Bool = true) -> Bool {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            print("Critical security risk detected. Cannot store private key.")
            return false
        }
        
        deletePrivateKey()
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: privateKeyTag,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecValueData as String: privateKey,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        if withBiometrics {
            var access: SecAccessControl?
            var error: Unmanaged<CFError>?
            
            access = SecAccessControlCreateWithFlags(
                kCFAllocatorDefault,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                [.biometryCurrentSet, .privateKeyUsage],
                &error
            )
            
            if let access = access {
                query[kSecAttrAccessControl as String] = access
            }
        }
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrievePrivateKey(reason: String = "Access your wallet") -> Data? {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            print("Critical security risk detected. Cannot retrieve private key.")
            return nil
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: privateKeyTag,
            kSecReturnData as String: true,
            kSecUseOperationPrompt as String: reason
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess, let data = result as? Data {
            return data
        }
        
        return nil
    }
    
    func deletePrivateKey() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: privateKeyTag
        ]
        
        SecItemDelete(query as CFDictionary)
    }
    
    func storeSecureData(_ data: Data, forKey key: String) -> Bool {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            return false
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrieveSecureData(forKey key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess, let data = result as? Data {
            return data
        }
        
        return nil
    }
}

// MARK: - Cryptographic Key Manager

class CryptoKeyManager {
    
    static let shared = CryptoKeyManager()
    
    private init() {}
    
    func generateNewKeyPair() -> (privateKey: Data, publicKey: Data, address: String)? {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            print("Critical security risk detected. Cannot generate keys.")
            return nil
        }
        
        let privateKey = P256.Signing.PrivateKey()
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyData = privateKey.publicKey.rawRepresentation
        
        let address = generateAddress(from: publicKeyData)
        
        return (privateKeyData, publicKeyData, address)
    }
    
    func generateAddress(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        let addressData = Data(hash.suffix(20))
        return "0x" + addressData.map { String(format: "%02x", $0) }.joined()
    }
    
    func signTransaction(_ transaction: Transaction, with privateKeyData: Data) -> Data? {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            print("Critical security risk detected. Cannot sign transaction.")
            return nil
        }
        
        do {
            let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
            let transactionData = transaction.serialize()
            let signature = try privateKey.signature(for: transactionData)
            return signature.rawRepresentation
        } catch {
            print("Error signing transaction: \(error)")
            return nil
        }
    }
    
    func verifySignature(_ signature: Data, for data: Data, publicKey: Data) -> Bool {
        do {
            let pubKey = try P256.Signing.PublicKey(rawRepresentation: publicKey)
            let sig = try P256.Signing.ECDSASignature(rawRepresentation: signature)
            return pubKey.isValidSignature(sig, for: data)
        } catch {
            return false
        }
    }
}

// MARK: - Transaction Model

struct Transaction {
    let from: String
    let to: String
    let amount: Decimal
    let nonce: UInt64
    let gasPrice: Decimal
    let gasLimit: UInt64
    let data: Data?
    
    func serialize() -> Data {
        var components: [String] = []
        components.append(from)
        components.append(to)
        components.append(amount.description)
        components.append(String(nonce))
        components.append(gasPrice.description)
        components.append(String(gasLimit))
        if let data = data {
            components.append(data.base64EncodedString())
        }
        
        let serialized = components.joined(separator: "|")
        return serialized.data(using: .utf8) ?? Data()
    }
}

// MARK: - Blockchain Communication Manager

class BlockchainManager {
    
    static let shared = BlockchainManager()
    
    private let baseURL = "https://api.blockchain.example.com"
    
    private init() {}
    
    func broadcastTransaction(_ transaction: Transaction, signature: Data, completion: @escaping (Result<String, Error>) -> Void) {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            completion(.failure(NSError(domain: "SecurityError", code: 403, userInfo: [NSLocalizedDescriptionKey: "Device security compromised"])))
            return
        }
        
        guard let url = URL(string: "\(baseURL)/transaction/broadcast") else {
            completion(.failure(NSError(domain: "URLError", code: 400, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let payload: [String: Any] = [
            "from": transaction.from,
            "to": transaction.to,
            "amount": transaction.amount.description,
            "nonce": transaction.nonce,
            "gasPrice": transaction.gasPrice.description,
            "gasLimit": transaction.gasLimit,
            "signature": signature.base64EncodedString(),
            "data": transaction.data?.base64EncodedString() ?? ""
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: payload)
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let txHash = json["transactionHash"] as? String else {
                completion(.failure(NSError(domain: "ParseError", code: 500, userInfo: nil)))
                return
            }
            
            completion(.success(txHash))
        }.resume()
    }
    
    func getBalance(for address: String, completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/balance/\(address)") else {
            completion(.failure(NSError(domain: "URLError", code: 400, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let balanceString = json["balance"] as? String,
                  let balance = Decimal(string: balanceString) else {
                completion(.failure(NSError(domain: "ParseError", code: 500, userInfo: nil)))
                return
            }
            
            completion(.success(balance))
        }.resume()
    }
    
    func getNonce(for address: String, completion: @escaping (Result<UInt64, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/nonce/\(address)") else {
            completion(.failure(NSError(domain: "URLError", code: 400, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let nonce = json["nonce"] as? UInt64 else {
                completion(.failure(NSError(domain: "ParseError", code: 500, userInfo: nil)))
                return
            }
            
            completion(.success(nonce))
        }.resume()
    }
}

// MARK: - Wallet Manager

class WalletManager {
    
    static let shared = WalletManager()
    
    private var currentAddress: String?
    private var publicKey: Data?
    
    private init() {}
    
    func createWallet(completion: @escaping (Result<String, Error>) -> Void) {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            completion(.failure(NSError(domain: "SecurityError", code: 403, userInfo: [NSLocalizedDescriptionKey: "Device security compromised. Cannot create wallet on this device."])))
            return
        }
        
        if securityCheck.riskLevel == .elevated {
            print("Warning: Elevated security risk detected")
        }
        
        guard let keyPair = CryptoKeyManager.shared.generateNewKeyPair() else {
            completion(.failure(NSError(domain: "KeyGenerationError", code: 500, userInfo: nil)))
            return
        }
        
        guard SecureStorageManager.shared.storePrivateKey(keyPair.privateKey, withBiometrics: true) else {
            completion(.failure(NSError(domain: "StorageError", code: 500, userInfo: nil)))
            return
        }
        
        let publicKeyData = keyPair.publicKey
        _ = SecureStorageManager.shared.storeSecureData(publicKeyData, forKey: "publicKey")
        _ = SecureStorageManager.shared.storeSecureData(keyPair.address.data(using: .utf8)!, forKey: "address")
        
        self.currentAddress = keyPair.address
        self.publicKey = publicKeyData
        
        completion(.success(keyPair.address))
    }
    
    func loadWallet() -> String? {
        guard let addressData = SecureStorageManager.shared.retrieveSecureData(forKey: "address"),
              let address = String(data: addressData, encoding: .utf8) else {
            return nil
        }
        
        self.currentAddress = address
        self.publicKey = SecureStorageManager.shared.retrieveSecureData(forKey: "publicKey")
        
        return address
    }
    
    func sendTransaction(to recipient: String, amount: Decimal, completion: @escaping (Result<String, Error>) -> Void) {
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        guard securityCheck.riskLevel != .critical else {
            completion(.failure(NSError(domain: "SecurityError", code: 403, userInfo: [NSLocalizedDescriptionKey: "Device security compromised. Transaction blocked."])))
            return
        }
        
        guard let address = currentAddress else {
            completion(.failure(NSError(domain: "WalletError", code: 400, userInfo: [NSLocalizedDescriptionKey: "No wallet loaded"])))
            return
        }
        
        BlockchainManager.shared.getNonce(for: address) { [weak self] result in
            switch result {
            case .success(let nonce):
                self?.continueTransaction(to: recipient, amount: amount, nonce: nonce, completion: completion)
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func continueTransaction(to recipient: String, amount: Decimal, nonce: UInt64, completion: @escaping (Result<String, Error>) -> Void) {
        guard let address = currentAddress else {
            completion(.failure(NSError(domain: "WalletError", code: 400, userInfo: nil)))
            return
        }
        
        let transaction = Transaction(
            from: address,
            to: recipient,
            amount: amount,
            nonce: nonce,
            gasPrice: Decimal(string: "0.00001")!,
            gasLimit: 21000,
            data: nil
        )
        
        guard let privateKeyData = SecureStorageManager.shared.retrievePrivateKey(reason: "Sign transaction") else {
            completion(.failure(NSError(domain: "AuthError", code: 401, userInfo: [NSLocalizedDescriptionKey: "Authentication failed"])))
            return
        }
        
        guard let signature = CryptoKeyManager.shared.signTransaction(transaction, with: privateKeyData) else {
            completion(.failure(NSError(domain: "SigningError", code: 500, userInfo: nil)))
            return
        }
        
        BlockchainManager.shared.broadcastTransaction(transaction, signature: signature, completion: completion)
    }
    
    func getBalance(completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let address = currentAddress else {
            completion(.failure(NSError(domain: "WalletError", code: 400, userInfo: [NSLocalizedDescriptionKey: "No wallet loaded"])))
            return
        }
        
        BlockchainManager.shared.getBalance(for: address, completion: completion)
    }
    
    func deleteWallet() {
        SecureStorageManager.shared.deletePrivateKey()
        currentAddress = nil
        publicKey = nil
    }
}

// MARK: - Main View Controller

class WalletViewController: UIViewController {
    
    private let addressLabel = UILabel()
    private let balanceLabel = UILabel()
    private let createWalletButton = UIButton(type: .system)
    private let sendButton = UIButton(type: .system)
    private let refreshButton = UIButton(type: .system)
    private let securityStatusLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        setupUI()
        performSecurityCheck()
        loadWalletIfExists()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Crypto Wallet"
        
        securityStatusLabel.translatesAutoresizingMaskIntoConstraints = false
        securityStatusLabel.textAlignment = .center
        securityStatusLabel.font = .systemFont(ofSize: 12, weight: .medium)
        securityStatusLabel.numberOfLines = 0
        view.addSubview(securityStatusLabel)
        
        addressLabel.translatesAutoresizingMaskIntoConstraints = false
        addressLabel.textAlignment = .center
        addressLabel.font = .systemFont(ofSize: 14, weight: .medium)
        addressLabel.numberOfLines = 0
        addressLabel.text = "No wallet"
        view.addSubview(addressLabel)
        
        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        balanceLabel.textAlignment = .center
        balanceLabel.font = .systemFont(ofSize: 32, weight: .bold)
        balanceLabel.text = "0.00"
        view.addSubview(balanceLabel)
        
        createWalletButton.translatesAutoresizingMaskIntoConstraints = false
        createWalletButton.setTitle("Create Wallet", for: .normal)
        createWalletButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        createWalletButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        view.addSubview(createWalletButton)
        
        sendButton.translatesAutoresizingMaskIntoConstraints = false
        sendButton.setTitle("Send", for: .normal)
        sendButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        sendButton.addTarget(self, action: #selector(sendTapped), for: .touchUpInside)
        sendButton.isHidden = true
        view.addSubview(sendButton)
        
        refreshButton.translatesAutoresizingMaskIntoConstraints = false
        refreshButton.setTitle("Refresh Balance", for: .normal)
        refreshButton.addTarget(self, action: #selector(refreshTapped), for: .touchUpInside)
        refreshButton.isHidden = true
        view.addSubview(refreshButton)
        
        NSLayoutConstraint.activate([
            securityStatusLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            securityStatusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            securityStatusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            addressLabel.topAnchor.constraint(equalTo: securityStatusLabel.bottomAnchor, constant: 30),
            addressLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            addressLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            balanceLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -50),
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            createWalletButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            createWalletButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 50),
            
            sendButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            sendButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 50),
            
            refreshButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            refreshButton.topAnchor.constraint(equalTo: sendButton.bottomAnchor, constant: 20)
        ])
    }
    
    private func performSecurityCheck() {
        let result = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        switch result.riskLevel {
        case .normal:
            securityStatusLabel.text = "✓ Device Secure"
            securityStatusLabel.textColor = .systemGreen
        case .elevated:
            securityStatusLabel.text = "⚠️ Security Warning\n\(result.warningChecks.joined(separator: ", "))"
            securityStatusLabel.textColor = .systemOrange
        case .critical:
            securityStatusLabel.text = "🚫 Critical Security Risk\n\(result.failedChecks.joined(separator: ", "))\n\nSensitive operations disabled"
            securityStatusLabel.textColor = .systemRed
            createWalletButton.isEnabled = false
            sendButton.isEnabled = false
        }
    }
    
    private func loadWalletIfExists() {
        if let address = WalletManager.shared.loadWallet() {
            addressLabel.text = address
            createWalletButton.isHidden = true
            sendButton.isHidden = false
            refreshButton.isHidden = false
            refreshBalance()
        }
    }
    
    @objc private func createWalletTapped() {
        let alert = UIAlertController(title: "Create Wallet", message: "This will generate a new wallet with a private key secured by biometrics.", preferredStyle: .alert)
        
        alert.addAction(UIAlertAction(title: "Create", style: .default) { [weak self] _ in
            WalletManager.shared.createWallet { result in
                DispatchQueue.main.async {
                    switch result {
                    case .success(let address):
                        self?.addressLabel.text = address
                        self?.createWalletButton.isHidden = true
                        self?.sendButton.isHidden = false
                        self?.refreshButton.isHidden = false
                        self?.refreshBalance()
                        self?.showAlert(title: "Success", message: "Wallet created successfully!")
                    case .failure(let error):
                        self?.showAlert(title: "Error", message: error.localizedDescription)
                    }
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func sendTapped() {
        let alert = UIAlertController(title: "Send Transaction", message: nil, preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Recipient Address"
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let recipient = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Decimal(string: amountString) else {
                self?.showAlert(title: "Error", message: "Invalid input")
                return
            }
            
            WalletManager.shared.sendTransaction(to: recipient, amount: amount) { result in
                DispatchQueue.main.async {
                    switch result {
                    case .success(let txHash):
                        self?.showAlert(title: "Success", message: "Transaction sent!\nHash: \(txHash)")
                        self?.refreshBalance()
                    case .failure(let error):
                        self?.showAlert(title: "Error", message: error.localizedDescription)
                    }
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func refreshTapped() {
        refreshBalance()
    }
    
    private func refreshBalance() {
        WalletManager.shared.getBalance { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.balanceLabel.text = balance.description
                case .failure(let error):
                    self?.showAlert(title: "Error", message: "Failed to fetch balance: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - App Delegate

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        let securityCheck = DeviceIntegrityChecker.shared.performComprehensiveSecurityCheck()
        
        if securityCheck.riskLevel == .critical {
            print("Critical security issues detected:")
            securityCheck.failedChecks.forEach { print("- \($0)") }
        }
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let viewController = WalletViewController()
        let navigationController = UINavigationController(rootViewController: viewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        return true
    }
}